var body = $input.first().json.body || $input.first().json;
var action = body.action || 'default';
// Route: output 0=init, 1=search, 2=match, 3=default
var idx = {'init':0,'search':1,'match':2}[action];
if (idx === undefined) idx = 3;
var items = [[],[],[],[]];
items[idx].push({json: $input.first().json});
return items;

// Core FAR/DFARS clauses relevant to GDA services contracts
var clauses = [
  {clause:'FAR 52.204-21',title:'Basic Safeguarding of Covered Contractor Info',category:'Cybersecurity',response:'GDA maintains NIST SP 800-171 compliant security controls across all information systems. Annual assessments conducted.'},
  {clause:'FAR 52.204-25',title:'Prohibition on Contracting for Hardware/Software from Covered Sources',category:'Supply Chain',response:'GDA certifies no use of covered telecommunications equipment or services per Section 889.'},
  {clause:'DFARS 252.204-7012',title:'Safeguarding Covered Defense Information',category:'Cybersecurity',response:'GDA implements NIST SP 800-171 controls and reports cyber incidents within 72 hours to DoD. CMMC Level 2 assessment in progress.'},
  {clause:'DFARS 252.204-7019',title:'NIST SP 800-171 DoD Assessment Requirements',category:'Cybersecurity',response:'GDA SPRS score submitted and current. Basic assessment completed within last 3 years.'},
  {clause:'DFARS 252.204-7020',title:'NIST SP 800-171 DoD Assessment Requirements (Medium/High)',category:'Cybersecurity',response:'GDA prepared for medium/high-level NIST assessment. POA&M maintained for any open items.'},
  {clause:'FAR 52.219-14',title:'Limitations on Subcontracting',category:'Small Business',response:'GDA monitors subcontracting ratios to ensure compliance. Primary services performed by GDA employees.'},
  {clause:'FAR 52.222-50',title:'Combating Trafficking in Persons',category:'Ethics',response:'GDA maintains anti-trafficking compliance plan and awareness training for all employees.'},
  {clause:'FAR 52.224-3',title:'Privacy Training',category:'Privacy',response:'All GDA employees complete annual privacy training. PII handling procedures documented and enforced.'},
  {clause:'DFARS 252.239-7010',title:'Cloud Computing Services',category:'Cloud',response:'GDA utilizes FedRAMP authorized cloud services. Data residency maintained within CONUS.'},
  {clause:'FAR 52.215-2',title:'Audit and Records',category:'Accounting',response:'GDA maintains DCAA-compliant accounting system. Records available for audit per contract requirements.'},
  {clause:'DFARS 252.227-7013',title:'Rights in Technical Data',category:'IP',response:'GDA delivers technical data with appropriate license rights per DFARS. Unlimited rights for government-funded development.'},
  {clause:'DFARS 252.227-7014',title:'Rights in Computer Software',category:'IP',response:'GDA delivers software with appropriate license rights. Government purpose rights for mixed-funded development.'},
  {clause:'FAR 52.232-39',title:'Unenforceability of Unauthorized Obligations',category:'Financial',response:'GDA does not recognize unauthorized commitments. All obligations require contracting officer authorization.'},
  {clause:'DFARS 252.204-7008',title:'Compliance with Safeguarding Requirements',category:'Cybersecurity',response:'GDA agrees to implement NIST SP 800-171 security requirements for covered contractor information systems.'},
  {clause:'FAR 52.237-3',title:'Continuity of Services',category:'Transition',response:'GDA provides 90-day transition support including knowledge transfer, documentation, and parallel operations.'},
  {clause:'DFARS 252.232-7003',title:'Electronic Submission of Payment Requests',category:'Financial',response:'GDA submits invoices electronically through WAWF/iRAPT per contract requirements.'},
  {clause:'FAR 52.245-1',title:'Government Property',category:'Property',response:'GDA maintains government property management system compliant with FAR 45. Annual inventories conducted.'},
  {clause:'DFARS 252.203-7002',title:'Requirement to Inform Employees of Whistleblower Rights',category:'Ethics',response:'GDA informs all employees of whistleblower protections. Hotline and reporting mechanisms established.'}
];

// Build SQL
var createTable = "CREATE TABLE IF NOT EXISTS gda_clause_library (id SERIAL PRIMARY KEY, clause_number VARCHAR(50) UNIQUE, title VARCHAR(500), category VARCHAR(100), standard_response TEXT, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW())";
var inserts = clauses.map(function(c) {
  return "INSERT INTO gda_clause_library (clause_number, title, category, standard_response) VALUES ('" + c.clause + "', '" + c.title.replace(/'/g,"''") + "', '" + c.category + "', '" + c.response.replace(/'/g,"''") + "') ON CONFLICT (clause_number) DO UPDATE SET standard_response = EXCLUDED.standard_response, updated_at = NOW()";
});

var sql = createTable + '; ' + inserts.join('; ') + ';';
return [{json:{sql:sql, clause_count:clauses.length}}];

var body = $input.first().json.body || {};
var planId = body.plan_id;
var contractType = (body.contract_type || '').toUpperCase();
var setAside = (body.set_aside || '').toUpperCase();
var naics = body.naics || '';

// Determine which clause categories are relevant
var categories = ['Cybersecurity','Ethics','Financial','Transition'];
if (setAside.includes('SMALL')) categories.push('Small Business');
if (contractType.includes('CLOUD') || naics === '541519') categories.push('Cloud');
if (contractType.includes('T&M') || contractType.includes('CPFF')) categories.push('Accounting');
categories.push('IP','Property','Privacy');

var categoryList = categories.map(function(c){return "'" + c + "'";}).join(',');
var sql = 'SELECT clause_number, title, category, standard_response FROM gda_clause_library WHERE category IN (' + categoryList + ') ORDER BY clause_number';

return [{json:{plan_id:planId, categories:categories, sql:sql}}];
